ALGORITHM TreeHeight(node)
BEGIN
  IF node = NULL THEN
    RETURN -1        // Empty tree has height -1
  ENDIF

  // Recursively find height of left and right subtrees
  leftHeight = TreeHeight(node.left)
  rightHeight = TreeHeight(node.right)

  // Return maximum height + 1 for current node
  RETURN MAX(leftHeight, rightHeight) + 1
END ALGORITHM

// Example with root node having two children:
// Height = 1 + max(height(leftSubtree), height(rightSubtree))

class TreeNode:
    def __init__(self, data):
        self.data = data
        self.left = None
        self.right = None

# Example: Creating a sample binary tree
#        10
#       /  \
#      5    15
#     / \
#    3   7

root = TreeNode(10)
root.left = TreeNode(5)
root.right = TreeNode(15)
root.left.left = TreeNode(3)
root.left.right = TreeNode(7)

# Function to count nodes
def count_nodes(node):
    if node is None:
        return 0
    return 1 + count_nodes(node.left) + count_nodes(node.right)

# Function to find depth of a node
def find_depth(node, target, current=0):
    if node is None:
        return -1
    if node.data == target:
        return current

    left_depth = find_depth(node.left, target, current + 1)
    if left_depth != -1:
        return left_depth
    return find_depth(node.right, target, current + 1)

print("Total nodes:", count_nodes(root))  # Output: 5
print("Depth of node 7:", find_depth(root, 7))  # Output: 2
